import json

with open('context/xiaohe.json', 'r') as f:
    xiaohe = json.load(f)

with open('context/problems.json', 'r') as f:
    problems = json.load(f)

shengmu_map = xiaohe['shengmu']
yunmu_map = xiaohe['yunmu']

# All valid pinyin syllables
VALID_SYLLABLES_PINYIN = set()

# Zero-initial (standalone finals)
for s in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng','er']:
    VALID_SYLLABLES_PINYIN.add(s)

# y-series (zero initial, i-vowel group)
for rest, yunmu in [('i','i'),('a','ia'),('e','ie'),('ao','iao'),('ou','iu'),
                     ('an','ian'),('in','in'),('ang','iang'),('ing','ing'),('ong','iong'),
                     ('u','v'),('ue','ve'),('uan','uan'),('un','un')]:
    VALID_SYLLABLES_PINYIN.add('y'+rest)

# w-series (zero initial, u-vowel group)
for rest, yunmu in [('u','u'),('a','ua'),('o','uo'),('ai','uai'),('ei','ui'),
                     ('an','uan'),('en','un'),('ang','uang'),('eng','ong')]:
    VALID_SYLLABLES_PINYIN.add('w'+rest)

# b p m
for sm in ['b','p','m']:
    for ym in ['a','o','ai','ei','ao','an','en','ang','eng','i','ie','iao','iu','ian','in','ing','u']:
        VALID_SYLLABLES_PINYIN.add(sm+ym)

# f
for ym in ['a','o','ei','ou','an','en','ang','eng','u']:
    VALID_SYLLABLES_PINYIN.add('f'+ym)

# d t
for sm in ['d','t']:
    for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
               'i','ie','iao','iu','ian','in','ing',
               'u','uo','uan','un']:
        VALID_SYLLABLES_PINYIN.add(sm+ym)

# n l
for sm in ['n','l']:
    for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
               'i','ia','ie','iao','iu','ian','in','ing','iang','iong',
               'u','uo','uan','un',
               'v','ve']:  # ü group
        VALID_SYLLABLES_PINYIN.add(sm+ym)

# g k h
for sm in ['g','k','h']:
    for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
               'u','ua','uo','uai','ui','uan','un','uang','ong']:
        VALID_SYLLABLES_PINYIN.add(sm+ym)

# j q x (i/ü group only)
for sm in ['j','q','x']:
    for ym in ['i','ia','ie','iao','iu','ian','in','ing','iang','iong',
               'v','ve','uan','un']:  # v=ü
        VALID_SYLLABLES_PINYIN.add(sm+ym)

# zh ch sh
for sm in ['zh','ch','sh']:
    for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
               'u','ua','uo','uai','ui','uan','un','uang','ong']:
        VALID_SYLLABLES_PINYIN.add(sm+ym)

# r
for ym in ['i','a','o','e','ao','ou','an','en','ang','eng','u','uo','uan','un','ong']:
    VALID_SYLLABLES_PINYIN.add('r'+ym)

# z c s
for sm in ['z','c','s']:
    for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
               'u','uo','uan','un','ong']:
        VALID_SYLLABLES_PINYIN.add(sm+ym)

print(f"Total valid pinyin syllables: {len(VALID_SYLLABLES_PINYIN)}")

# Convert pinyin syllable to Xiaohe 2-char code
def syllable_to_xiaohe(syl):
    # Try non-zero shengmu (longest match first)
    for sm in sorted([s for s in shengmu_map if s], key=len, reverse=True):
        if syl.startswith(sm):
            rest = syl[len(sm):]
            if rest in yunmu_map:
                return shengmu_map[sm] + yunmu_map[rest]

    # Zero-initial: y-series
    if syl.startswith('y'):
        rest = syl[1:]
        y_to_ym = {
            'i':'i','a':'ia','e':'ie','ao':'iao','ou':'iu',
            'an':'ian','in':'in','ang':'iang','ing':'ing','ong':'iong',
            'u':'v','ue':'ve','uan':'uan','un':'un',
        }
        if rest in y_to_ym:
            ym = y_to_ym[rest]
            if ym in yunmu_map:
                return shengmu_map['y'] + yunmu_map[ym]

    # Zero-initial: w-series
    if syl.startswith('w'):
        rest = syl[1:]
        w_to_ym = {
            'u':'u','a':'ua','o':'uo','ai':'uai','ei':'ui',
            'an':'uan','en':'un','ang':'uang','eng':'ong',
        }
        if rest in w_to_ym:
            ym = w_to_ym[rest]
            if ym in yunmu_map:
                return shengmu_map['w'] + yunmu_map[ym]

    # Zero-initial: a/o/e single vowel/finals
    # e.g., 'an' -> first key 'a', yunmu 'an' key 'j' -> 'aj'
    # Try: first char is the "leading vowel key", second is yunmu key
    if syl in yunmu_map:
        first_key = syl[0]  # a, o, e
        return first_key + yunmu_map[syl]

    return None

# Build valid Xiaohe code set
valid_codes = set()
code_debug = {}
for syl in VALID_SYLLABLES_PINYIN:
    code = syllable_to_xiaohe(syl)
    if code:
        valid_codes.add(code)
        code_debug.setdefault(code, []).append(syl)

print(f"Valid Xiaohe 2-char codes: {len(valid_codes)}")

# Verify some important ones
checks = ['de', 'le', 'ge', 'he', 'jia', 'qing', 'xin', 'zhong', 'an', 'yi', 'wu',
          'shi', 'zhi', 'chi', 'ri', 'zi', 'ci', 'si', 'er', 'ai', 'ao',
          'na', 'ge', 'xu', 'yi', 'dui', 'guo', 'zhe', 'jue']
for c in checks:
    code = syllable_to_xiaohe(c)
    print(f"  {c} -> {code}  {'✓' if code in valid_codes else '✗'}")

# Show all valid codes
print(f"\nAll {len(valid_codes)} valid codes:")
print(sorted(valid_codes))
