"""
Solve with cross-validation between similar problem strings.
"""

import json
from itertools import product

with open('context/xiaohe.json') as f:
    xiaohe = json.load(f)
with open('context/problems.json') as f:
    problems = json.load(f)

shengmu_map = xiaohe['shengmu']
yunmu_map = xiaohe['yunmu']

# ---- Build valid codes (from solve6) ----
def make_valid_codes():
    codes = set()
    def add(sm_key, ym_key):
        if sm_key and ym_key:
            codes.add(sm_key + ym_key)
    def add_pm(sm_p, ym_p):
        add(shengmu_map.get(sm_p), yunmu_map.get(ym_p))

    for ym in ['a','ai','ao','an','ang']: codes.add('a' + yunmu_map[ym])
    for ym in ['o','ou']: codes.add('o' + yunmu_map[ym])
    for ym in ['e','ei','en','eng','er']: codes.add('e' + yunmu_map[ym])

    # y-series: use surface vowel keys + contracted forms
    y_surface = ['i','a','e','ao','ou','an','in','ang','ing','ong','v','ve','uan','un']
    y_contracted = ['ia','ie','iao','iu','ian','iang','iong']
    for ym in y_surface + y_contracted:
        if ym in yunmu_map: codes.add('y' + yunmu_map[ym])

    # w-series: surface + contracted
    w_surface = ['u','a','o','ai','ei','an','en','ang','eng']
    w_contracted = ['ua','uo','uai','ui','uan','un','uang','ong']
    for ym in w_surface + w_contracted:
        if ym in yunmu_map: codes.add('w' + yunmu_map[ym])

    for sm in ['b','p','m']:
        for ym in ['a','o','ai','ei','ao','an','en','ang','eng','i','ie','iao','iu','ian','in','ing','u']:
            add_pm(sm, ym)
    add_pm('m', 'e')

    for ym in ['a','o','ei','ou','an','en','ang','eng','u']:
        add_pm('f', ym)

    for sm in ['d','t']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ie','iao','iu','ian','in','ing','u','uo','uan','un','ui','ong']:
            add_pm(sm, ym)

    for sm in ['n','l']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ia','ie','iao','iu','ian','in','ing','iang','iong',
                   'u','uo','uan','un','ui','v','ve','ong']:
            add_pm(sm, ym)

    for sm in ['g','k','h']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']:
            add_pm(sm, ym)

    for sm in ['j','q','x']:
        for ym in ['i','ia','ie','iao','iu','ian','in','ing','iang','iong','v','ve','uan','un']:
            add_pm(sm, ym)

    for sm in ['zh','ch','sh']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']:
            add_pm(sm, ym)

    for ym in ['i','a','o','e','ao','ou','an','en','ang','eng','u','uo','uan','un','ong']:
        add_pm('r', ym)

    for sm in ['z','c','s']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','uo','uan','un','ong','ui']:
            add_pm(sm, ym)

    return codes

valid_codes = make_valid_codes()

def count_valid(s):
    if len(s) % 2 != 0: return 0
    return sum(1 for i in range(0, len(s), 2) if s[i:i+2] in valid_codes)

def is_fully_valid(s):
    if len(s) % 2 != 0: return False
    return all(s[i:i+2] in valid_codes for i in range(0, len(s), 2))

def get_all_candidates(s):
    """Return dict: score -> [positions]"""
    from collections import defaultdict
    d = defaultdict(list)
    for i in range(len(s)):
        cand = s[:i] + s[i+1:]
        d[count_valid(cand)].append(i)
    return d

# Typing heuristics
QWERTY_ROWS = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
ADJACENCY = {}
for row_i, row in enumerate(QWERTY_ROWS):
    for col_j, c in enumerate(row):
        nb = set()
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                r2,c2 = row_i+dr, col_j+dc
                if 0<=r2<len(QWERTY_ROWS) and 0<=c2<len(QWERTY_ROWS[r2]):
                    if (dr,dc) != (0,0): nb.add(QWERTY_ROWS[r2][c2])
        ADJACENCY[c] = nb

def heuristic_score(s, pos):
    c = s[pos]
    score = 0
    if pos > 0 and s[pos-1] == c: score += 10
    if pos < len(s)-1 and s[pos+1] == c: score += 10
    if pos > 0 and s[pos-1] in ADJACENCY.get(c, set()): score += 3
    if pos < len(s)-1 and s[pos+1] in ADJACENCY.get(c, set()): score += 3
    return score

# ---- Find best candidate sets ----
all_cands = []
for idx, s in enumerate(problems):
    d = get_all_candidates(s)
    best_score = max(d.keys())
    best_pos = d[best_score]
    all_cands.append((idx, best_score, best_pos))

# ---- Cross-validation: find pairs of similar problems ----
def find_common_deletions(s1, s2):
    """Find (p1, p2) pairs where removing s1[p1] == removing s2[p2]."""
    result = []
    # Build deletion dict for s2
    s2_deletions = {}
    for p2 in range(len(s2)):
        c2 = s2[:p2] + s2[p2+1:]
        if c2 not in s2_deletions:
            s2_deletions[c2] = []
        s2_deletions[c2].append(p2)
    # Check s1 deletions
    for p1 in range(len(s1)):
        c1 = s1[:p1] + s1[p1+1:]
        if c1 in s2_deletions:
            for p2 in s2_deletions[c1]:
                result.append((p1, p2))
    return result

# Find similar pairs and cross-validate
n = len(problems)
cross_constraints = {}  # idx -> set of valid positions (from cross-val)

for i in range(n):
    for j in range(i+1, n):
        s1, s2 = problems[i], problems[j]
        if abs(len(s1) - len(s2)) > 2:
            continue
        # Quick similarity check
        min_len = min(len(s1), len(s2))
        matches = sum(c1==c2 for c1,c2 in zip(s1,s2))
        if matches < min_len * 0.75:
            continue

        # Find common deletions
        common = find_common_deletions(s1, s2)
        if common:
            # Filter by valid scores
            _, best_i, cands_i = all_cands[i]
            _, best_j, cands_j = all_cands[j]

            valid_common = [(p1,p2) for p1,p2 in common 
                          if p1 in cands_i and p2 in cands_j]

            if valid_common:
                # Intersect constraints
                p1s = set(p1 for p1,p2 in valid_common)
                p2s = set(p2 for p1,p2 in valid_common)

                if i not in cross_constraints:
                    cross_constraints[i] = p1s
                else:
                    cross_constraints[i] &= p1s
                    if not cross_constraints[i]:
                        cross_constraints[i] = p1s  # reset if empty

                if j not in cross_constraints:
                    cross_constraints[j] = p2s
                else:
                    cross_constraints[j] &= p2s
                    if not cross_constraints[j]:
                        cross_constraints[j] = p2s

                if len(p1s) <= 3 or len(p2s) <= 3:
                    print(f"Cross [{i}]x[{j}]: p1={sorted(p1s)} p2={sorted(p2s)}")

print(f"\nCross-constrained problems: {sorted(cross_constraints.keys())}")

# ---- Final results ----
results = [-1] * 100

for idx, best_score, best_pos in all_cands:
    s = problems[idx]
    candidates = best_pos

    # Apply cross-constraints
    if idx in cross_constraints:
        constrained = [p for p in candidates if p in cross_constraints[idx]]
        if constrained:
            candidates = constrained

    if len(candidates) == 1:
        results[idx] = candidates[0]
    else:
        # Tiebreak with heuristics
        hscores = [(heuristic_score(s, p), p) for p in candidates]
        best_h = max(h for h, _ in hscores)
        best_h_pos = [p for h, p in hscores if h == best_h]
        results[idx] = best_h_pos[0]

fully_valid = sum(1 for idx, s in enumerate(problems) if is_fully_valid(s[:results[idx]] + s[results[idx]+1:]))
print(f"\nFully valid: {fully_valid}/100")
print(f"Results: {results}")

# Save
with open('output.json', 'w') as f:
    json.dump(results, f)
print("Saved output.json")
