    if not pi_after: pi_after = pi
    if len(pi_after) > 1:
        remaining_ambig += 1

print(f"Remaining ambiguous after cross-val: {remaining_ambig}")
print(f"\nResults: {results}")

with open('output.json', 'w') as f:
