{"content": "#!/usr/bin/env python3
"""
FINAL SOLUTION: Xiaohe double-pinyin extra character detection.

Approach:
1. Build valid Xiaohe 2-char codes (fixing zero-initial y/w series to use surface vowels)
2. For each problem, find positions that give max valid-pair coverage
3. Cross-validate using pairs of problems that share the same underlying sentence
4. For remaining ambiguous cases, use typing heuristics (doubled chars, adjacent keys)
   and prefer smaller index among tied doubled-char positions
"""

import json
from collections import defaultdict

with open('context/xiaohe.json') as f:
    xiaohe = json.load(f)
with open('context/problems.json') as f:
    problems = json.load(f)

shengmu_map = xiaohe['shengmu']
yunmu_map = xiaohe['yunmu']

# ===== Step 1: Build valid Xiaohe codes =====

def make_valid_codes():
    codes = set()
    def adp(sp, yp):
        sk = shengmu_map.get(sp)
        yk = yunmu_map.get(yp)
        if sk and yk:
            codes.add(sk + yk)

    # Zero-initial a/e/o series (first letter = pseudo-shengmu key)
    for ym in ['a', 'ai', 'ao', 'an', 'ang']:
        codes.add('a' + yunmu_map[ym])
    for ym in ['o', 'ou']:
        codes.add('o' + yunmu_map[ym])
    for ym in ['e', 'ei', 'en', 'eng', 'er']:
        codes.add('e' + yunmu_map[ym])

    # y-series: surface vowel keys (you→yz, yao→yc, yan→yj, yang→yh, etc.)
    # AND contracted forms for consonant-initial (iu→q for liu/xiu etc.)
    y_yms = ['i', 'a', 'e', 'ao', 'ou', 'an', 'in', 'ang', 'ing', 'ong',
             'v', 've', 'uan', 'un',       # these are always the same
             'ia', 'ie', 'iao', 'iu', 'ian', 'iang', 'iong']  # contracted forms
    for ym in y_yms:
        if ym in yunmu_map:
            codes.add('y' + yunmu_map[ym])

    # w-series: surface vowel keys + contracted forms
    w_yms = ['u', 'a', 'o', 'ai', 'ei', 'an', 'en', 'ang', 'eng',
             'ua', 'uo', 'uai', 'ui', 'uan', 'un', 'uang', 'ong']
    for ym in w_yms:
        if ym in yunmu_map:
            codes.add('w' + yunmu_map[ym])

    # b p m
    for sm in ['b', 'p', 'm']:
        for ym in ['a', 'o', 'ai', 'ei', 'ao', 'an', 'en', 'ang', 'eng',
                   'i', 'ie', 'iao', 'iu', 'ian', 'in', 'ing', 'u']:
            adp(sm, ym)
    adp('m', 'e')  # 么

    # f
    for ym in ['a', 'o', 'ei', 'ou', 'an', 'en', 'ang', 'eng', 'u']:
        adp('f', ym)

    # d t
    for sm in ['d', 't']:
        for ym in ['a', 'o', 'e', 'ai', 'ei', 'ao', 'ou', 'an', 'en', 'ang', 'eng',
                   'i', 'ie', 'iao', 'iu', 'ian', 'in', 'ing',
                   'u', 'uo', 'uan', 'un', 'ui', 'ong']:
            adp(sm, ym)

    # n l
    for sm in ['n', 'l']:
        for ym in ['a', 'o', 'e', 'ai', 'ei', 'ao', 'ou', 'an', 'en', 'ang', 'eng',
                   'i', 'ia', 'ie', 'iao', 'iu', 'ian', 'in', 'ing', 'iang', 'iong',
                   'u', 'uo', 'uan', 'un', 'ui', 'v', 've', 'ong']:
            adp(sm, ym)

    # g k h
    for sm in ['g', 'k', 'h']:
        for ym in ['a', 'o', 'e', 'ai', 'ei', 'ao', 'ou', 'an', 'en', 'ang', 'eng',
                   'u', 'ua', 'uo', 'uai', 'ui', 'uan', 'un', 'uang', 'ong']:
            adp(sm, ym)

    # j q x (i/ü group only)
    for sm in ['j', 'q', 'x']:
        for ym in ['i', 'ia', 'ie', 'iao', 'iu', 'ian', 'in', 'ing', 'iang', 'iong',
                   'v', 've', 'uan', 'un']:
            adp(sm, ym)

    # zh ch sh
    for sm in ['zh', 'ch', 'sh']:
        for ym in ['i', 'a', 'o', 'e', 'ai', 'ei', 'ao', 'ou', 'an', 'en', 'ang', 'eng',
                   'u', 'ua', 'uo', 'uai', 'ui', 'uan', 'un', 'uang', 'ong']:
            adp(sm, ym)

    # r
    for ym in ['i', 'a', 'o', 'e', 'ao', 'ou', 'an', 'en', 'ang', 'eng',
               'u', 'uo', 'uan', 'un', 'ong']:
        adp('r', ym)

    # z c s
    for sm in ['z', 'c', 's']:
        for ym in ['i', 'a', 'o', 'e', 'ai', 'ei', 'ao', 'ou', 'an', 'en', 'ang', 'eng',
                   'u', 'uo', 'uan', 'un', 'ong', 'ui']:
            adp(sm, ym)

    return codes

valid_codes = make_valid_codes()

def count_valid(s):
    if len(s) % 2 != 0:
        return 0
    return sum(1 for i in range(0, len(s), 2) if s[i:i+2] in valid_codes)

def is_fully_valid(s):
    if len(s) % 2 != 0:
        return False
    return all(s[i:i+2] in valid_codes for i in range(0, len(s), 2))

def get_best_positions(s):
    """Return (best_score, [positions]) for max valid-pair deletions."""
    best_v = -1
    best_p = []
    for i in range(len(s)):
        c = s[:i] + s[i+1:]
        v = count_valid(c)
        if v > best_v:
            best_v, best_p = v, [i]
        elif v == best_v:
            best_p.append(i)
    return best_v, best_p

# ===== Step 2: Compute best positions for all problems =====

all_best_scores = []
all_best_positions = []
for s in problems:
    bv, bp = get_best_positions(s)
    all_best_scores.append(bv)
    all_best_positions.append(bp)

# ===== Step 3: Cross-validation =====

def find_common_deletions(s1, best_p1, s2, best_p2):
    """Find (p1,p2) pairs where deleting s1[p1]==deleting s2[p2], within best candidates."""
    # Build deletion dict for s2 restricted to best positions
    d2 = {}
    for p2 in best_p2:
        c2 = s2[:p2] + s2[p2+1:]
        d2.setdefault(c2, []).append(p2)
    result = []
    for p1 in best_p1:
        c1 = s1[:p1] + s1[p1+1:]
        if c1 in d2:
            for p2 in d2[c1]:
                result.append((p1, p2))
    return result

# Initialize constraints as "all best positions are valid"
constraints = {i: set(all_best_positions[i]) for i in range(len(problems))}

# Multi-round cross-validation (propagate constraints)
for _ in range(5):  # multiple rounds to propagate chains
    for i in range(len(problems)):
        for j in range(i+1, len(problems)):
            s1, s2 = problems[i], problems[j]
            if abs(len(s1) - len(s2)) > 2:
                continue
            min_len = min(len(s1), len(s2))
            if sum(c1==c2 for c1,c2 in zip(s1,s2)) < min_len * 0.70:
                continue

            # Use current constraints
            p1_cands = list(constraints[i])
            p2_cands = list(constraints[j])

            common = find_common_deletions(s1, p1_cands, s2, p2_cands)
            if common:
                new_p1 = set(p for p,_ in common)
                new_p2 = set(p for _,p in common)

                # Intersect with existing constraints
                intersect_p1 = constraints[i] & new_p1
                intersect_p2 = constraints[j] & new_p2

                if intersect_p1:
                    constraints[i] = intersect_p1
                if intersect_p2:
                    constraints[j] = intersect_p2

# ===== Step 4: Heuristic tiebreaking =====

QWERTY_ROWS = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
ADJ = {}
for ri, row in enumerate(QWERTY_ROWS):
    for ci, c in enumerate(row):
        nb = set()
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                r2, c2 = ri+dr, ci+dc
                if 0<=r2<len(QWERTY_ROWS) and 0<=c2<len(QWERTY_ROWS[r2]) and (dr,dc)!=(0,0):
                    nb.add(QWERTY_ROWS[r2][c2])
        ADJ[c] = nb

def heuristic_score(s, pos):
    c = s[pos]
    score = 0
    # Doubled char (strongest signal)
    if pos > 0 and s[pos-1] == c:
        score += 100
    if pos < len(s)-1 and s[pos+1] == c:
        score += 100
    # Adjacent key on QWERTY
    if pos > 0 and s[pos-1] in ADJ.get(c, set()):
        score += 30
    if pos < len(s)-1 and s[pos+1] in ADJ.get(c, set()):
        score += 30
    # Prefer later position for same-char pairs (consistent with "extra key press")
    score += pos * 0.01
    return score

# ===== Step 5: Final answer selection =====

results = []
for idx, s in enumerate(problems):
    candidates = sorted(constraints[idx])

    if len(candidates) == 1:
        results.append(candidates[0])
    else:
        # Pick by heuristic
        best_pos = max(candidates, key=lambda p: heuristic_score(s, p))
        results.append(best_pos)

# ===== Validation =====

fully_valid = sum(
    1 for idx, s in enumerate(problems)
    if is_fully_valid(s[:results[idx]] + s[results[idx]+1:])
)
print(f"Fully valid: {fully_valid}/100")

# Check constraint sizes
unique = sum(1 for idx in range(len(problems)) if len(constraints[idx]) == 1)
print(f"Uniquely determined by cross-val: {unique}/100")

ambiguous = [(idx, sorted(constraints[idx])) for idx in range(len(problems)) if len(constraints[idx]) > 1]
print(f"Ambiguous after cross-val: {len(ambiguous)}/100")

# For debugging: show which ones remain ambiguous
for idx, cands in ambiguous[:20]:
    s = problems[idx]
    print(f"  [{idx}] candidates={cands[:8]}, chosen={results[idx]} ({s[results[idx]]!r})")

print(f"\nResults: {results}")

# Save output
with open('output.json', 'w') as f:
    json.dump(results, f)
print("Saved output.json")
