{"content": "#!/usr/bin/env python3
"""
Solve the Xiaohe double-pinyin extra character problem.

Strategy:
1. Build valid Xiaohe 2-char code set
2. For each problem string (odd length), try removing each position
3. Score candidates by how many valid 2-char pairs they produce
4. For pairs of similar strings (same sentence), use cross-validation
5. Use typing error heuristics (adjacent key, doubled char) as tiebreaker
"""

import json
from collections import defaultdict

with open('context/xiaohe.json') as f:
    xiaohe = json.load(f)
with open('context/problems.json') as f:
    problems = json.load(f)

shengmu_map = xiaohe['shengmu']
yunmu_map = xiaohe['yunmu']

# ---- Build valid Xiaohe 2-char code set ----

def make_valid_codes():
    codes = set()
    def add(sm_p, ym_p):
        sm_key = shengmu_map.get(sm_p)
        ym_key = yunmu_map.get(ym_p)
        if sm_key is not None and ym_key is not None:
            codes.add(sm_key + ym_key)

    # Zero-initial: a/e/o series
    for ym in ['a','ai','ao','an','ang']:
        codes.add('a' + yunmu_map[ym])
    for ym in ['o','ou']:
        codes.add('o' + yunmu_map[ym])
    for ym in ['e','ei','en','eng','er']:
        codes.add('e' + yunmu_map[ym])

    # y-series: yi ya ye yao you yan yin yang ying yong yu yue yuan yun
    for ym in ['i','ia','ie','iao','iu','ian','in','iang','ing','iong','v','ve','uan','un']:
        add('y', ym)

    # w-series: wu wa wo wai wei wan wen wang weng
    for ym in ['u','ua','uo','uai','ui','uan','un','uang','ong']:
        add('w', ym)

    # b p m
    for sm in ['b','p','m']:
        for ym in ['a','o','ai','ei','ao','an','en','ang','eng',
                   'i','ie','iao','iu','ian','in','ing','u']:
            add(sm, ym)

    # f
    for ym in ['a','o','ei','ou','an','en','ang','eng','u']:
        add('f', ym)

    # d t
    for sm in ['d','t']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ie','iao','iu','ian','in','ing',
                   'u','uo','uan','un']:
            add(sm, ym)

    # n l (add ü group + iang/iong)
    for sm in ['n','l']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ia','ie','iao','iu','ian','in','ing','iang','iong',
                   'u','uo','uan','un',
                   'v','ve']:
            add(sm, ym)

    # g k h
    for sm in ['g','k','h']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']:
            add(sm, ym)

    # j q x (ü written as v in phoneme notation)
    for sm in ['j','q','x']:
        for ym in ['i','ia','ie','iao','iu','ian','in','ing','iang','iong',
                   'v','ve','uan','un']:
            add(sm, ym)

    # zh ch sh
    for sm in ['zh','ch','sh']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']:
            add(sm, ym)

    # r
    for ym in ['i','a','o','e','ao','ou','an','en','ang','eng','u','uo','uan','un','ong']:
        add('r', ym)

    # z c s
    for sm in ['z','c','s']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','uo','uan','un','ong']:
            add(sm, ym)

    return codes

valid_codes = make_valid_codes()
print(f"Valid Xiaohe 2-char codes: {len(valid_codes)}")

# ---- Scoring function ----

def count_valid_pairs(s):
    """Count how many 2-char pairs in s are valid Xiaohe codes."""
    if len(s) % 2 != 0:
        return 0
    count = 0
    for i in range(0, len(s), 2):
        if s[i:i+2] in valid_codes:
            count += 1
    return count

def total_pairs(s):
    return len(s) // 2

def is_fully_valid(s):
    if len(s) % 2 != 0:
        return False
    return all(s[i:i+2] in valid_codes for i in range(0, len(s), 2))

def get_candidate_scores(s):
    """
    For each deletion position, return the number of valid pairs.
    Returns list of (score, position).
    """
    n = len(s)
    scores = []
    for i in range(n):
        cand = s[:i] + s[i+1:]
        score = count_valid_pairs(cand)
        scores.append((score, i))
    return scores

# ---- Typing error heuristics ----
# QWERTY keyboard adjacency (for scoring likely typos)
QWERTY_ROWS = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
ADJACENCY = {}
for row_i, row in enumerate(QWERTY_ROWS):
    for col_j, c in enumerate(row):
        neighbors = set()
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                r2, c2 = row_i + dr, col_j + dc
                if 0 <= r2 < len(QWERTY_ROWS) and 0 <= c2 < len(QWERTY_ROWS[r2]):
                    if (dr, dc) != (0, 0):
                        neighbors.add(QWERTY_ROWS[r2][c2])
        ADJACENCY[c] = neighbors

def is_adjacent_to_nearby(s, pos):
    """Check if s[pos] is adjacent to s[pos-1] or s[pos+1] on QWERTY."""
    c = s[pos]
    if pos > 0 and s[pos-1] in ADJACENCY.get(c, set()):
        return True
    if pos < len(s)-1 and s[pos+1] in ADJACENCY.get(c, set()):
        return True
    return False

def is_doubled(s, pos):
    """Check if s[pos] == s[pos-1] or s[pos+1] (accidental double press)."""
    c = s[pos]
    if pos > 0 and s[pos-1] == c:
        return True
    if pos < len(s)-1 and s[pos+1] == c:
        return True
    return False

def heuristic_score(s, pos):
    """Higher = more likely to be a typing error at this position."""
    score = 0
    if is_doubled(s, pos):
        score += 3
    if is_adjacent_to_nearby(s, pos):
        score += 1
    return score

# ---- Find extra character for each problem ----

# First pass: find best candidates using valid pairs count
results = [-1] * 100
confidence = [0] * 100

for idx, s in enumerate(problems):
    n = len(s)
    max_pairs = n // 2  # total pairs if one char removed

    scores = get_candidate_scores(s)
    best_score = max(sc for sc, _ in scores)
    best_positions = [pos for sc, pos in scores if sc == best_score]

    if len(best_positions) == 1:
        results[idx] = best_positions[0]
        confidence[idx] = best_score
    else:
        # Tiebreak with typing heuristics
        hscores = [(heuristic_score(s, pos), pos) for pos in best_positions]
        best_h = max(h for h, _ in hscores)
        best_h_positions = [pos for h, pos in hscores if h == best_h]

        if len(best_h_positions) == 1:
            results[idx] = best_h_positions[0]
        else:
            results[idx] = best_h_positions[0]  # just pick first
        confidence[idx] = best_score

# Print summary
fully_valid = sum(1 for idx, s in enumerate(problems) if is_fully_valid(s[:results[idx]] + s[results[idx]+1:]))
print(f"Fully valid after deletion: {fully_valid}/100")

# Show details for non-fully-valid ones
for idx, s in enumerate(problems):
    pos = results[idx]
    cand = s[:pos] + s[pos+1:]
    if not is_fully_valid(cand):
        scores = get_candidate_scores(s)
        best_score = max(sc for sc, _ in scores)
        best_positions = [p for sc, p in scores if sc == best_score]
        n_pairs = total_pairs(cand)
        print(f"[{idx}] pos={pos} score={confidence[idx]}/{n_pairs} best_positions={best_positions[:6]}")
        # Show the bad pairs
        bad_pairs = [(i//2, cand[i:i+2]) for i in range(0, len(cand), 2) if cand[i:i+2] not in valid_codes]
        print(f"      bad pairs: {bad_pairs[:5]}")

print(f"\nResults: {results}")
