{"content": "#!/usr/bin/env python3
"""
Final solution: comprehensive approach with cross-validation and heuristics.
"""

import json
from collections import defaultdict

with open('context/xiaohe.json') as f:
    xiaohe = json.load(f)
with open('context/problems.json') as f:
    problems = json.load(f)

shengmu_map = xiaohe['shengmu']
yunmu_map = xiaohe['yunmu']

# ---- Build valid codes ----
def make_valid_codes():
    codes = set()
    def add(sk, yk):
        if sk and yk: codes.add(sk + yk)
    def adp(sp, yp):
        add(shengmu_map.get(sp), yunmu_map.get(yp))

    for ym in ['a','ai','ao','an','ang']: codes.add('a'+yunmu_map[ym])
    for ym in ['o','ou']: codes.add('o'+yunmu_map[ym])
    for ym in ['e','ei','en','eng','er']: codes.add('e'+yunmu_map[ym])
    for ym in ['i','a','e','ao','ou','an','in','ang','ing','ong','v','ve','uan','un',
               'ia','ie','iao','iu','ian','iang','iong']:
        if ym in yunmu_map: codes.add('y'+yunmu_map[ym])
    for ym in ['u','a','o','ai','ei','an','en','ang','eng',
               'ua','uo','uai','ui','uan','un','uang','ong']:
        if ym in yunmu_map: codes.add('w'+yunmu_map[ym])
    for sm in ['b','p','m']:
        for ym in ['a','o','ai','ei','ao','an','en','ang','eng','i','ie','iao','iu','ian','in','ing','u']: adp(sm,ym)
    adp('m','e')
    for ym in ['a','o','ei','ou','an','en','ang','eng','u']: adp('f',ym)
    for sm in ['d','t']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ie','iao','iu','ian','in','ing','u','uo','uan','un','ui','ong']: adp(sm,ym)
    for sm in ['n','l']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ia','ie','iao','iu','ian','in','ing','iang','iong',
                   'u','uo','uan','un','ui','v','ve','ong']: adp(sm,ym)
    for sm in ['g','k','h']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']: adp(sm,ym)
    for sm in ['j','q','x']:
        for ym in ['i','ia','ie','iao','iu','ian','in','ing','iang','iong','v','ve','uan','un']: adp(sm,ym)
    for sm in ['zh','ch','sh']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']: adp(sm,ym)
    for ym in ['i','a','o','e','ao','ou','an','en','ang','eng','u','uo','uan','un','ong']: adp('r',ym)
    for sm in ['z','c','s']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','uo','uan','un','ong','ui']: adp(sm,ym)
    return codes

valid_codes = make_valid_codes()

def count_valid(s):
    if len(s)%2!=0: return 0
    return sum(1 for i in range(0,len(s),2) if s[i:i+2] in valid_codes)

def is_valid(s):
    if len(s)%2!=0: return False
    return all(s[i:i+2] in valid_codes for i in range(0,len(s),2))

def get_best(s):
    best_v = -1
    best_p = []
    for i in range(len(s)):
        c = s[:i]+s[i+1:]
        v = count_valid(c)
        if v > best_v: best_v, best_p = v, [i]
        elif v == best_v: best_p.append(i)
    return best_v, best_p

# ---- Cross-validation ----
def find_common_deletions(s1, s2):
    d2 = defaultdict(list)
    for p2 in range(len(s2)):
        d2[s2[:p2]+s2[p2+1:]].append(p2)
    result = []
    for p1 in range(len(s1)):
        c1 = s1[:p1]+s1[p1+1:]
        if c1 in d2:
            for p2 in d2[c1]:
                result.append((p1,p2))
    return result

# Get best positions for all problems
all_best = [get_best(s) for s in problems]

# Find cross-validation constraints
cross = defaultdict(set)  # idx -> set of valid positions

for i in range(len(problems)):
    for j in range(i+1, len(problems)):
        s1, s2 = problems[i], problems[j]
        if abs(len(s1)-len(s2)) > 2: continue
        min_len = min(len(s1),len(s2))
        if sum(c1==c2 for c1,c2 in zip(s1,s2)) < min_len*0.70: continue

        bi, pi = all_best[i]
        bj, pj = all_best[j]
        common = find_common_deletions(s1, s2)

        valid = [(p1,p2) for p1,p2 in common if p1 in pi and p2 in pj]
        if valid:
            p1s = set(p for p,_ in valid)
            p2s = set(p for _,p in valid)
            if not cross[i]: cross[i] = p1s
            else: cross[i] &= p1s
            if not cross[i]: cross[i] = p1s

            if not cross[j]: cross[j] = p2s
            else: cross[j] &= p2s
            if not cross[j]: cross[j] = p2s

# ---- Typing heuristics ----
QWERTY = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
ADJ = {}
for ri, row in enumerate(QWERTY):
    for ci, c in enumerate(row):
        nb = set()
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                r2,c2 = ri+dr, ci+dc
                if 0<=r2<len(QWERTY) and 0<=c2<len(QWERTY[r2]) and (dr,dc)!=(0,0):
                    nb.add(QWERTY[r2][c2])
        ADJ[c] = nb

def h_score(s, pos):
    c = s[pos]
    sc = 0
    # Repeated char (doubled)
    if pos>0 and s[pos-1]==c: sc += 10
    if pos<len(s)-1 and s[pos+1]==c: sc += 10
    # Adjacent key
    if pos>0 and s[pos-1] in ADJ.get(c,set()): sc += 3
    if pos<len(s)-1 and s[pos+1] in ADJ.get(c,set()): sc += 3
    # Later position slightly preferred (for same-char repetitions)
    sc += pos * 0.001
    return sc

# ---- Final selection ----
results = []
for idx, s in enumerate(problems):
    bi, pi = all_best[idx]

    # Apply cross-validation constraints
    if idx in cross and cross[idx]:
        pi_filtered = [p for p in pi if p in cross[idx]]
        if pi_filtered:
            pi = pi_filtered

    if len(pi) == 1:
        results.append(pi[0])
    else:
        # Use heuristics
        best_h = max(pi, key=lambda p: h_score(s, p))
        results.append(best_h)

# ---- Validate ----
fully_valid = sum(1 for idx,s in enumerate(problems) if is_valid(s[:results[idx]]+s[results[idx]+1:]))
print(f"Fully valid: {fully_valid}/100")

# Show remaining ambiguous (where best_pos > 1 even after cross-val)
remaining_ambig = 0
for idx, s in enumerate(problems):
    bi, pi = all_best[idx]
    pi_after = [p for p in pi if idx not in cross or not cross[idx] or p in cross[idx]]
    if not pi_after: pi_after = pi
    if len(pi_after) > 1:
        remaining_ambig += 1

print(f"Remaining ambiguous after cross-val: {remaining_ambig}")
print(f"\nResults: {results}")

with open('output.json', 'w') as f:
    json.dump(results, f)
print("Saved output.json")
