{"content": "#!/usr/bin/env python3
"""
FINAL SOLUTION for Xiaohe double-pinyin extra character detection.
"""

import json
from collections import defaultdict

with open('context/xiaohe.json') as f:
    xiaohe = json.load(f)
with open('context/problems.json') as f:
    problems = json.load(f)

shengmu_map = xiaohe['shengmu']
yunmu_map = xiaohe['yunmu']

# ===== Build valid Xiaohe 2-char codes =====

def make_valid_codes():
    codes = set()
    def adp(sp, yp):
        sk = shengmu_map.get(sp)
        yk = yunmu_map.get(yp)
        if sk and yk:
            codes.add(sk + yk)

    for ym in ['a','ai','ao','an','ang']: codes.add('a'+yunmu_map[ym])
    for ym in ['o','ou']: codes.add('o'+yunmu_map[ym])
    for ym in ['e','ei','en','eng','er']: codes.add('e'+yunmu_map[ym])

    for ym in ['i','a','e','ao','ou','an','in','ang','ing','ong','v','ve','uan','un',
               'ia','ie','iao','iu','ian','iang','iong']:
        if ym in yunmu_map: codes.add('y'+yunmu_map[ym])

    for ym in ['u','a','o','ai','ei','an','en','ang','eng',
               'ua','uo','uai','ui','uan','un','uang','ong']:
        if ym in yunmu_map: codes.add('w'+yunmu_map[ym])

    for sm in ['b','p','m']:
        for ym in ['a','o','ai','ei','ao','an','en','ang','eng','i','ie','iao','iu','ian','in','ing','u']:
            adp(sm, ym)
    adp('m', 'e')

    for ym in ['a','o','ei','ou','an','en','ang','eng','u']:
        adp('f', ym)

    for sm in ['d','t']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ie','iao','iu','ian','in','ing','u','uo','uan','un','ui','ong']:
            adp(sm, ym)

    for sm in ['n','l']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'i','ia','ie','iao','iu','ian','in','ing','iang','iong',
                   'u','uo','uan','un','ui','v','ve','ong']:
            adp(sm, ym)

    for sm in ['g','k','h']:
        for ym in ['a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']:
            adp(sm, ym)

    for sm in ['j','q','x']:
        for ym in ['i','ia','ie','iao','iu','ian','in','ing','iang','iong','v','ve','uan','un']:
            adp(sm, ym)

    for sm in ['zh','ch','sh']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','ua','uo','uai','ui','uan','un','uang','ong']:
            adp(sm, ym)

    for ym in ['i','a','o','e','ao','ou','an','en','ang','eng','u','uo','uan','un','ong']:
        adp('r', ym)

    for sm in ['z','c','s']:
        for ym in ['i','a','o','e','ai','ei','ao','ou','an','en','ang','eng',
                   'u','uo','uan','un','ong','ui']:
            adp(sm, ym)

    return codes

valid_codes = make_valid_codes()

def count_valid(s):
    if len(s)%2!=0: return 0
    return sum(1 for i in range(0,len(s),2) if s[i:i+2] in valid_codes)

def is_fully_valid(s):
    if len(s)%2!=0: return False
    return all(s[i:i+2] in valid_codes for i in range(0,len(s),2))

def get_best_positions(s):
    best_v = -1; best_p = []
    for i in range(len(s)):
        c = s[:i]+s[i+1:]
        v = count_valid(c)
        if v > best_v: best_v,best_p = v,[i]
        elif v == best_v: best_p.append(i)
    return best_v, best_p

# ===== Cross-validation =====

def find_common_deletions_filtered(s1, cands1, s2, cands2):
    d2 = defaultdict(list)
    for p2 in cands2:
        d2[s2[:p2]+s2[p2+1:]].append(p2)
    result = []
    for p1 in cands1:
        c1 = s1[:p1]+s1[p1+1:]
        if c1 in d2:
            for p2 in d2[c1]: result.append((p1,p2))
    return result

all_best = [get_best_positions(s) for s in problems]
constraints = {i: set(all_best[i][1]) for i in range(len(problems))}

for _ in range(10):
    changed = False
    for i in range(len(problems)):
        for j in range(i+1, len(problems)):
            s1, s2 = problems[i], problems[j]
            if abs(len(s1)-len(s2)) > 2: continue
            if sum(c1==c2 for c1,c2 in zip(s1,s2)) < min(len(s1),len(s2))*0.70: continue

            common = find_common_deletions_filtered(
                s1, list(constraints[i]),
                s2, list(constraints[j])
            )
            if common:
                new_p1 = set(p for p,_ in common)
                new_p2 = set(p for _,p in common)
                inter1 = constraints[i] & new_p1
                inter2 = constraints[j] & new_p2
                if inter1 and inter1 != constraints[i]:
                    constraints[i] = inter1; changed = True
                if inter2 and inter2 != constraints[j]:
                    constraints[j] = inter2; changed = True
    if not changed:
        break

# ===== Heuristic tiebreaking =====

QWERTY_ROWS = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
ADJ = {}
for ri, row in enumerate(QWERTY_ROWS):
    for ci, c in enumerate(row):
        nb = set()
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                r2,c2 = ri+dr,ci+dc
                if 0<=r2<len(QWERTY_ROWS) and 0<=c2<len(QWERTY_ROWS[r2]) and (dr,dc)!=(0,0):
                    nb.add(QWERTY_ROWS[r2][c2])
        ADJ[c] = nb

def heuristic_score(s, pos):
    c = s[pos]
    score = 0
    # Doubled char: strongest signal
    if pos > 0 and s[pos-1] == c:
        score += 1000
        score += pos  # prefer later position of doubled pair
    if pos < len(s)-1 and s[pos+1] == c:
        score += 1000
        score -= pos  # prefer earlier position when next char is same (we're the extra one)
    # Adjacent key
    if pos > 0 and s[pos-1] in ADJ.get(c,set()): score += 30
    if pos < len(s)-1 and s[pos+1] in ADJ.get(c,set()): score += 30
    return score

# ===== Final selection =====

results = []
for idx, s in enumerate(problems):
    cands = sorted(constraints[idx])
    if len(cands) == 1:
        results.append(cands[0])
    else:
        # Among tied candidates, prefer doubled chars
        doubled = [p for p in cands if 
                   (p > 0 and s[p-1] == s[p]) or 
                   (p < len(s)-1 and s[p+1] == s[p])]
        if doubled:
            # Pick the LATER one of each doubled pair (the "re-press")
            # Sort by: which is the second of a consecutive same-char run
            def is_second_in_run(p):
                return p > 0 and s[p-1] == s[p]

            def is_first_in_run(p):
                return p < len(s)-1 and s[p+1] == s[p]

            # Second-in-run candidates first, then first-in-run
            second_run = [p for p in doubled if is_second_in_run(p)]
            if second_run:
                # Pick the one with the highest position (last repeated char)
                results.append(max(second_run))
            else:
                results.append(max(doubled))
        else:
            # Fallback: adjacent key heuristic
            hs = [(heuristic_score(s, p), p) for p in cands]
            best_h = max(hs, key=lambda x: x[0])
            results.append(best_h[1])

# ===== Validation =====
fv = sum(1 for idx,s in enumerate(problems) if is_fully_valid(s[:results[idx]]+s[results[idx]+1:]))
print(f"Fully valid: {fv}/100")
unique = sum(1 for idx in range(len(problems)) if len(constraints[idx])==1)
print(f"Uniquely determined: {unique}/100")

print(f"\nResults: {results}")
with open('output.json','w') as f:
    json.dump(results,f)
print("Saved output.json")
